# stubs/llm_stub.py
# Lightweight OpenAI-compatible stub server for preview environments.
# Returns deterministic canned responses so PR reviewers can test the full UI flow.

from fastapi import FastAPI, Request
from pydantic import BaseModel
import json, hashlib

app = FastAPI()

CANNED_RESPONSES = {
    "rag_answer": {
        "answer": "Based on the provided context, retrieval augmented generation (RAG) combines a retrieval system with a language model to produce grounded, accurate responses.",
        "sources": [{"title": "RAG Overview", "url": "https://example.internal/rag"}],
    },
    "summarization": {
        "summary": "This document describes the key concepts of the topic in three concise sentences.",
    },
    "classification": {
        "category": "technical_question",
        "confidence": 0.92,
    },
}

@app.post("/v1/chat/completions")
async def chat_completions(request: Request):
    body = await request.json()
    system_prompt = next(
        (m["content"] for m in body.get("messages", []) if m["role"] == "system"),
        ""
    )

    # Pick canned response by matching system prompt keywords
    response_key = "rag_answer"
    if "summar" in system_prompt.lower():
        response_key = "summarization"
    elif "classif" in system_prompt.lower():
        response_key = "classification"

    canned = CANNED_RESPONSES[response_key]
    content = json.dumps(canned) if body.get("response_format", {}).get("type") == "json_object" else str(canned)

    return {
        "id": f"stub-{hashlib.sha256(system_prompt.encode()).hexdigest()[:8]}",
        "object": "chat.completion",
        "model": body.get("model", "stub-model"),
        "choices": [{
            "index": 0,
            "message": {"role": "assistant", "content": content},
            "finish_reason": "stop",
        }],
        "usage": {"prompt_tokens": 100, "completion_tokens": 50, "total_tokens": 150},
    }

@app.get("/health")
def health():
    return {"status": "ok", "mode": "stub"}
